// ─── VP CONCEPT ───────────────────────────────────────────────────────────
function VPConcept() {
  return (
    <Shell>
      <Header num="02" tag="Concepts" title="What is Volume Profile?"
        subtitle="A visual representation of where traders were willing to trade — based on auction theory. Price gravitates toward high-volume nodes because that is where the market found fair value." />
      <div className="slide-enter-delay-1" style={{ display:"flex", gap:24 }}>
        <div style={{ flex:"0 0 500px" }}>
          <Card style={{ padding:0, overflow:"hidden" }}>
            <img src={IMG_VPCONCEPT} alt="VP Components & Normal Distribution" style={{ width:"100%", display:"block" }}/>
          </Card>
        </div>
        <div style={{ flex:1, display:"flex", flexDirection:"column", gap:12 }}>
          {[
            { label:"POC", full:"Point of Control", color:C.red, faint:C.redFaint,
              desc:"The price level with the highest traded volume. The market's fairest price — price is magnetically drawn back to the POC." },
            { label:"VAH", full:"Value Area High", color:C.teal, faint:C.tealFaint,
              desc:"Upper boundary of the 70% volume zone. Closing above VAH signals the market accepted higher prices — a bullish expansion." },
            { label:"VAL", full:"Value Area Low", color:C.teal, faint:C.tealFaint,
              desc:"Lower boundary of the 70% volume zone. Closing below VAL signals bearish rejection of fair value." },
            { label:"70%", full:"The Value Area Rule", color:C.gold, faint:C.goldFaint,
              desc:"Rooted in CBOT Market Profile methodology. Expand from POC until 70% of total session volume is captured — that zone is 'fair value'." },
          ].map((x,i) => (
            <Accent key={i} color={x.color} faint={x.faint}>
              <div style={{ display:"flex", gap:12, alignItems:"flex-start" }}>
                <div style={{
                  background:x.color, color:"#080C12", borderRadius:6, padding:"5px 10px",
                  fontSize:12, fontWeight:800, flexShrink:0, fontFamily:"'JetBrains Mono',monospace",
                }}>{x.label}</div>
                <div>
                  <div style={{ fontSize:12, fontWeight:700, color:C.white, marginBottom:4, fontFamily:"Inter,sans-serif" }}>{x.full}</div>
                  <div style={{ fontSize:11, color:C.offwhite, lineHeight:1.65, fontFamily:"Inter,sans-serif" }}>{x.desc}</div>
                </div>
              </div>
            </Accent>
          ))}
        </div>
      </div>
    </Shell>
  );
}

